class ChatGPTAI {
  constructor() {
      this.root = "https://free.gpt.ge/v1/chat/completions"; // ChatGPT API 端点
      this.apiKey = "sk-kP59Dy3oFrmwO6YXAf869eA4A8B94749916868E6A4B84869"; // 替换为你的 API 密钥
      this.headers = {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${this.apiKey}`
      };
      this.aiTalkMode = false;
      this.aiPostExplanation = '';
  }

  init() {
      if (!document.querySelector(".ai-explanation")) return;
      this.aiTalkMode = false;
      this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;
      if (!this.aiPostExplanation) {
          this.generate();
      } else {
          this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
      }
      this.AIEngine();
  }

  getTitleAndContent() {
      const e = document.getElementById("article-container"),
          t = document.title,
          n = e.getElementsByTagName("p"),
          i = e.querySelectorAll("h1, h2, h3, h4, h5");
      return (t + " " + Array.from(i).concat(Array.from(n)).map(e => e.innerText.replace(/https?:\/\/[^\s]+/g, "")).join(" ")).slice(0, 1000);
  }

  async generate() {
      this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent()));
  }

  async fetch(title, content) {
      const response = await fetch(this.root, {
          method: 'POST',
          headers: this.headers,
          body: JSON.stringify({
              prompt: `${title}\n${content}`, // 将标题和内容作为提示传递
              max_tokens: 150, // 根据需要调整生成的最大令牌数
              temperature: 0.7, // 创造性参数
              top_p: 1.0,
              frequency_penalty: 0.0,
              presence_penalty: 0.0
          })
      });
      const data = await response.json();
      if (response.ok) {
          this.aiPostExplanation = data.choices[0].text.trim();
          return data.choices[0].text.trim();
      } else {
          console.error("Request failed:", data.error);
          return data.error;
      }
  }

  aiShowAnimation(promise) {
      const n = document.querySelector(".ai-explanation"),
          i = document.querySelector(".ai-tag");
      if (!n || this.aiTalkMode) return;
      this.aiTalkMode = true;
      this.cleanSuggestions();
      i.classList.add("loadingAI");
      n.style.display = "block";
      n.innerHTML = '生成中...<span class="blinking-cursor"></span>';
      let s, o, a = true, c = 0, r = true;
      const l = new IntersectionObserver((e => { a = e[0].isIntersecting; a && requestAnimationFrame(o) }), { threshold: 0 });
      promise.then(e => {
          s = performance.now();
          o = () => {
              if (c < e.length && a) {
                  const r = performance.now(),
                      g = r - s,
                      h = e.slice(c, c + 1),
                      u = /[，。！、？,.!?]/.test(h),
                      m = /[a-zA-Z0-9]/.test(h);
                  g >= (u ? 100 * Math.random() + 100 : m ? 10 : 25) && (n.innerText = e.slice(0, c + 1), s = r, c++, c < e.length ? n.innerHTML = e.slice(0, c) + '<span class="blinking-cursor"></span>' : (n.innerHTML = e, n.style.display = "block", this.aiTalkMode = false, i.classList.remove("loadingAI"), l.disconnect()));
              }
              a && requestAnimationFrame(o)
          };
          a && r && setTimeout(() => { requestAnimationFrame(o); r = false; }, 3000);
          l.observe(n)
      }).catch(e => {
          console.error("检索信息失败：", e);
          n.innerHTML = "检索信息失败";
          n.style.display = "block";
          this.aiTalkMode = false;
          i.classList.remove("loadingAI");
          l.disconnect()
      })
  }

  AIEngine() {
      const e = document.querySelector(".ai-tag");
      e && e.addEventListener("click", () => {
          this.aiTalkMode || (this.aiTalkMode = true, this.aiShowAnimation(Promise.resolve(this.aiPostExplanation)))
      });
  }

  cleanSuggestions() {
      const e = document.querySelector(".ai-suggestions");
      e ? e.innerHTML = "" : console.error("没有这个元素：'ai-suggestions'");
  }

  createSuggestions() {
      this.aiTalkMode && (this.cleanSuggestions(), this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
          "" === this.aiPostExplanation ? this.generate() : this.aiShowAnimation(Promise.resolve(this.aiPostExplanation))
      }), PAGE_CONFIG.randomPost && this.createSuggestionItemWithAction("带我去看看其他文章", toRandomPost), this.aiTalkMode = true);
  }

  createSuggestionItemWithAction(e, t) {
      const n = document.querySelector(".ai-suggestions");
      if (!n) return void console.error("无法找到具有class为ai-suggestions的元素");
      const i = document.createElement("div");
      i.classList.add("ai-suggestions-item"), i.textContent = e, i.addEventListener("click", t), n.appendChild(i)
  }
}

const chatGPTAI = new ChatGPTAI;
chatGPTAI.init();